module top_module( clk, data_in, reset, data_out);output data_out; 
  input clk; 
  input data_in; 
  input reset; 
  reg sync_reg ; 
  reg data_out ; 
  always @(posedge clk or posedge reset) 
  begin 
  if (reset == 1) sync_reg <= 1; 
  else sync_reg <= data_in; 
  end 
  always @(posedge clk or posedge reset) 
  begin 
  if (reset == 1) data_out <= 1; 
  else data_out <= sync_reg; 
  end 
 endmodule
